def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    pres = Presentation(modified_ppt_path)
    slide_idx = 2
    slide = pres.slides[slide_idx]
    for shape in slide.shapes:
        if shape.has_table:
            tbl = shape.table
            # At least two rows (or columns) required: one for type names, others for characteristics
            if tbl.rows.__len__() > 1 or tbl.columns.__len__() > 1:
                # Heuristic: there should be at least one cell whose text is not a worm type
                expected_types = ["roundworm", "flatworm", "segmented worm"]
                type_set = set(expected_types)
                cells = [cell.text.strip().lower() for row in tbl.rows for cell in row.cells]
                # If there is any cell not containing a worm type name, table is not just listing names
                others = [cell for cell in cells if all(t not in cell for t in type_set)]
                if len(others) > 0:
                    return "Table contains characteristics beyond worm type names.", 1.0
                else:
                    return "Table only contains worm type names.", 0.0
            else:
                return "Table is too small to compare characteristics.", 0.0
    return "No table found to check characteristics.", 0.0

